listitem.programlisting:
rabbitmq().
  consume {
    queue("user")
    connection {
      host = hostContainer
      port = portContainer
      password = "defaultpass"
      username = "user"
    }
    concurrency(2)
    prefetchCount (11)
}

rabbitmq().
  produce {
    name = "my-producer-step"
    concurrency(10)
    connection {
      host = "anotherhost"
      port = 5673
      password = "pass"
      username = "test"
      virtualHost = "/guest"
      clientProperties = mapOf("t" to "test")
      }
    records(recordSupplier)
    monitoring {
      events = true
      meters = false
    }
}
